#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode *left;
    struct TreeNode *right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*) malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to check if two trees are mirror images of each other
int isMirror(TreeNode* t1, TreeNode* t2) {
    if (t1 == NULL && t2 == NULL)
        return 1;
    if (t1 == NULL || t2 == NULL)
        return 0;
    return (t1->val == t2->val) && isMirror(t1->left, t2->right) && isMirror(t1->right, t2->left);
}

// Function to check if a binary tree is symmetric
int isSymmetric(TreeNode* root) {
    if (root == NULL)
        return 1;
    return isMirror(root->left, root->right);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* values = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &values[i]);
        }
        // Create the binary tree from the level-order traversal
        TreeNode* root = createTreeNode(values[0]);
        TreeNode** queue = (TreeNode**)malloc(N * sizeof(TreeNode*));
        int front = 0, rear = 0;
        queue[rear++] = root;
        int idx = 1;
        while (front < rear && idx < N) {
            TreeNode* temp = queue[front++];
            if (values[idx] != -1) {
                temp->left = createTreeNode(values[idx]);
                queue[rear++] = temp->left;
            }
            idx++;
            if (idx < N && values[idx] != -1) {
                temp->right = createTreeNode(values[idx]);
                queue[rear++] = temp->right;
            }
            idx++;
        }
        printf("%s\n", isSymmetric(root) ? "true" : "false");
        free(values);
        free(queue);
    }
    return 0;
}

